276			return false, fmt.Sprintf("cannot read beads file %s: %v", beadsFile, err)
277		}
278		defer f.Close()
279		sc := bufio.NewScanner(f)
280		sc.Buffer(make([]byte, 0, 64*1024), 4*1024*1024)
281		for sc.Scan() {
282			line := sc.Bytes()
283			if len(line) == 0 {
284				continue
285			}
286			var rec struct {
287				ID     string `json:"id"`
288				Status string `json:"status"`
289			}
290			if err := json.Unmarshal(line, &rec); err != nil {
291				continue
292			}
293			if rec.ID == beadID {
294				if rec.Status == "open" || rec.Status == "in_progress" || rec.Status == "ready" {
295					return true, ""
296				}
297				return false, fmt.Sprintf("bead %s status=%q (must be open)", beadID, rec.Status)
298			}
